#include <vector>
#include <queue>
#include <unordered_map>

using namespace std;

long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    int n = grid[0].size();
    vector<vector<bool>> visited(m, vector<bool>(n, false));
    long long count = 0;

    // Directions for up, down, left, right
    int dx[] = {0, 0, -1, 1};
    int dy[] = {-1, 1, 0, 0};

    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            if (grid[i][j] > 0 && !visited[i][j]) {
                queue<pair<int, int>> q;
                q.push({i, j});
                visited[i][j] = true;
                long long islandSum = grid[i][j];
                long long mod = islandSum % k;

                while (!q.empty()) {
                    int x = q.front().first;
                    int y = q.front().second;
                    q.pop();

                    for (int d = 0; d < 4; ++d) {
                        int nx = x + dx[d];
                        int ny = y + dy[d];
                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && !visited[nx][ny] && grid[nx][ny] > 0) {
                            visited[nx][ny] = true;
                            islandSum += grid[nx][ny];
                            mod = islandSum % k;
                            q.push({nx, ny});
                        }
                    }
                }

                if (mod == 0) {
                    ++count;
                }
            }
        }
    }

    return count;
}

