                q.push({i, j});
                visited[i][j] = true;
                long long islandSum = grid[i][j];
                long long mod = islandSum % k;

                while (!q.empty()) {
                    int x = q.front().first;
                    int y = q.front().second;
                    q.pop();

                    for (int d = 0; d < 4; ++d) {
